import{_ as a,o as t,c as o,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"Facebook Platform Ads","description":"","frontmatter":{"title":"Facebook Platform Ads","slug":"facebook-platform-ads"},"headers":[],"relativePath":"marketer-hub/facebook-platform-ads.md","filePath":"marketer-hub/facebook-platform-ads.md"}'),i={name:"marketer-hub/facebook-platform-ads.md"};function r(s,e,d,l,c,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch Links can be used together with a variety of Facebook ads, allowing you to track ad performance on the Branch dashboard and to deep link new users from ad-driven installs directly to content the first time they open your app.</p><p>Note: This documentation applies for Ad placements across Facebook and the Audience Network.</p><p>This documentation supports the following Facebook Ad Campaign types:</p><table tabindex="0"><thead><tr><th>Facebook Campaign Category</th><th>Campaign Type/Objective</th><th>Branch Ad Format</th></tr></thead><tbody><tr><td>Awareness</td><td>Brand Awareness</td><td>Cross-platform Display</td></tr><tr><td>Awareness</td><td>Reach</td><td>Cross-platform Display</td></tr><tr><td>Consideration</td><td>Video Views</td><td>Cross-platform Display</td></tr><tr><td>Consideration</td><td>Lead Generation</td><td>Cross-platform Display</td></tr></tbody></table><h4 id="facebook-campaign-advert-format-support-table" tabindex="-1">Facebook Campaign Advert Format Support Table <a class="header-anchor" href="#facebook-campaign-advert-format-support-table" aria-label="Permalink to &quot;Facebook Campaign Advert Format Support Table&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Facebook Campaign Type</th><th>Photo</th><th>Video</th><th>Carousel</th><th>Slideshow</th><th>Collection</th><th>Dynamic</th><th>Canvas</th></tr></thead><tbody><tr><td>Brand Awareness</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td><td></td><td>✔︎</td></tr><tr><td>Reach</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td><td></td><td>✔︎</td></tr><tr><td>Video Views</td><td></td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td><td></td><td>✔︎</td></tr><tr><td>Lead Generation</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td>✔︎</td><td></td><td></td><td></td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Facebook Campaign Types</p><p>Looking for other Facebook Ad campaign types? Please check out our <a href="./facebook-ads-overview.html">Facebook Ads Overview guide</a>.</p></div><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisites</p><ul><li>To track installs from Facebook Ads you should <a href="./native-sdks-overview.html">integrate the Branch SDK</a> into your app.</li><li>To use Branch Links in Facebook App Install Ads ensure you have Universal Links set up on iOS or App Links enabled on Android to ensure correct routing behavior. For setup, check out <a href="https://help.branch.io/developers-hub/docs/ios-universal-links" target="_blank" rel="noreferrer">Universal</a> and <a href="https://help.branch.io/developers-hub/docs/android-app-links" target="_blank" rel="noreferrer">App Links</a>.</li><li>If you want to deep link from your ads directly to content, you should <a href="./deep-linking.html">configure deep link routing</a>.</li><li>Ads is a premium product priced on Monthly Active Users. Sign up for the Ads product to enable this functionality.&quot;</li></ul></div><h4 id="enable-facebook-as-an-ad-partner-for-measurement" tabindex="-1">Enable Facebook as an Ad Partner (for measurement) <a class="header-anchor" href="#enable-facebook-as-an-ad-partner-for-measurement" aria-label="Permalink to &quot;Enable Facebook as an Ad Partner (for measurement)&quot;">​</a></h4><div class="info custom-block"><p class="custom-block-title">Enable Facebook as an Ad Partner</p><p>Completing this section -- <strong>Enable Facebook as an Ad Partner</strong> -- will result in Branch sending app events to Facebook in order to attribute them back to ad campaigns. <strong>This does not enable deep linking for the ad</strong>. Further work below is required for deep linking.</p></div><p>If you haven&#39;t enabled Facebook as an Ad Partner on the Branch Dashboard follow this section to do so. Advanced options for sending events can be found <a href="./facebook-faq-and-advanced-options.html">here</a>.</p><ol><li><p>Navigate to the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management tab</a>.</p></li><li><p>Search for <strong>Facebook</strong>.</p></li><li><p>Click <strong>Connect With Facebook</strong></p></li><li><p>Log in to Facebook if you are not logged in</p></li><li><p>Confirm that Branch can receive your public profile</p></li><li><p>Confirm that Branch can have permissions <code>ads_read</code></p></li></ol><p><code>ads_read</code> is used to surface impressions and clicks on the Branch Dashboard.</p><ol start="7"><li>Select the ad accounts for which you want to run app install ads or app engagement ads</li></ol><div class="info custom-block"><p class="custom-block-title">Ad Account FAQ</p><p>If you are having trouble finding or selecting the ad account(s) for which you want to run ads, please visit our <a href="https://help.branch.io/faq/docs/i-cant-see-the-ad-account-i-want-to-use-at-all" target="_blank" rel="noreferrer">FAQ</a>.</p></div><ol start="8"><li><p>Click to select a Facebook app id for which you want to run Facebook ads</p></li><li><p>Copy the app id</p></li><li><p>Paste the app id and press <code>Save</code></p></li><li><p>Facebook is now enabled as an ad partner!</p><p>Note that if you have different attribution windows between Facebook and Branch, those will be highlighted. The warning has a link to the docs on how to align these attribution windows.</p></li><li><p>Finally, to create a Facebook Ads link click the <strong>Create Facebook Link</strong> button in the top right hand corner.</p></li></ol><h5 id="create-an-ad-link" tabindex="-1">Create an Ad Link <a class="header-anchor" href="#create-an-ad-link" aria-label="Permalink to &quot;Create an Ad Link&quot;">​</a></h5><ol><li><p>Create a Branch Ad link from the <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer">Partner Management page</a>&#39;s <strong>Create Facebook Link</strong> button under the Facebook Partner and select <strong>Create Display Link</strong> or <strong>Create Display Link</strong> depending on your campaign type.</p></li><li><p>Pick a Link Name for later reference.</p></li><li><p>Configure the link the Ad Partner set to <strong>Facebook</strong> and the Ad Format set to <strong>Cross-Platform Display</strong> or <strong>Cross-platform Display</strong>.</p></li><li><p>Under the Configure Options tab, navigate to the Redirects sub section and ensure that the iOS/Android and Desktop redirects are set to the desired destinations being promoted by the ad campaign.</p></li><li><p>Under the Analytics Tags sub-section additional tags can be set. It is recommended to fill in these fields as they can be used as filters in Branch&#39;s Ads Analytics view. To best connect your ad link with your Facebook Campaign, set the channel field to Facebook Ads and set the campaign field to the same ad campaign name used in Facebook Ads.</p></li></ol><p>.png&quot;)</p><div class="warning custom-block"><p class="custom-block-title">Disabling Deepviews</p><p>In order for your campaign to run effectively, be sure to disable Deepviews. You can either [disable Deepviews]((/using-branch/docs/deepviews) for your entire account or <a href="./deepviews.html">disable Deepviews for one link</a>.</p></div><div class="info custom-block"><p class="custom-block-title">Optional: Deep Link Data</p><p>You can use this configuration section to specify custom link parameters that will be deep linked into the app after install. These could include a coupon code or a page identifier to route the user. Visit the <a href="./deep-linking.html">Deep Link Routing</a> page to learn more.</p></div><h4 id="brand-awareness-campaign-setup" tabindex="-1">Brand Awareness Campaign Setup <a class="header-anchor" href="#brand-awareness-campaign-setup" aria-label="Permalink to &quot;Brand Awareness Campaign Setup&quot;">​</a></h4><h5 id="configure-an-ad" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up Facebook Brand Awareness Campaigns, you will need to insert your Branch Ad Link as the Website destination for the created ad.</p><h5 id="create-your-campaign" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li><p>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</p></li><li><p>Select <strong>Brand Awareness</strong> as the campaign marketing objective.</p></li><li><p>Continue with campaign creation selecting the app to advertise, audience, placement, and budget. Then press continue to enter the Advert creation step.</p></li><li><p>Now select an advertisement format and customize your ad</p></li><li><p>Now add your Branch Link to your advertisement</p><ul><li>Select the <strong>Add a Website URL</strong> checkbox and copy your Branch Ad Link into the <strong>Website URL</strong> field.</li></ul></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- If you selected to add a full screen Canvas advertisement, add your Branch Ad link as the &lt;span class=&quot;notranslate&quot;&gt;**Destination URL**&lt;/span&gt; for your canvas advertisement components</span></span></code></pre></div><ol start="6"><li>Complete the rest of the ad campaign setup.</li></ol><div class="info custom-block"><p class="custom-block-title">Optional: Ad formats with Multiple Links</p><div class="info custom-block"><p class="custom-block-title">Optional: Ad formats with Multiple Links</p><div class="info custom-block"><p class="custom-block-title">Optional: Ad formats with Multiple Links</p><p>Some ad formats such as Carousel format can handle multiple deep links. To have link performance data on each image or component of the advertisement, create multiple Branch Ad links to be used in each part of the multiple link advertisement format. This format is useful if you want to drive customers to different content pieces or products.</p></div></div></div><p>:::</p><p>:::</p><h4 id="reach-campaign-setup" tabindex="-1">Reach Campaign Setup <a class="header-anchor" href="#reach-campaign-setup" aria-label="Permalink to &quot;Reach Campaign Setup&quot;">​</a></h4><h5 id="configure-an-ad-1" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad-1" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up Facebook Reach Campaigns, you will need to insert your Branch Ad Link as the Website destination for the created ad.</p><h5 id="create-your-campaign-1" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign-1" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li><p>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</p></li><li><p>Select <strong>Reach</strong> as the campaign marketing objective.</p></li><li><p>Continue with campaign creation selecting the app to advertise, audience, placement, and budget. Then press continue to enter the Advert creation step.</p></li><li><p>Now select an advertisement format and customize your ad</p></li><li><p>Now add your Branch Link to your advertisement</p><ul><li>Select the <strong>Add a Website URL</strong> checkbox and copy your Branch Ad Link into the <strong>Website URL</strong> field.</li></ul></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- If you selected to add a full screen Canvas advertisement, add your Branch Ad link as the &lt;span class=&quot;notranslate&quot;&gt;**Destination URL**&lt;/span&gt; for your canvas advertisement components</span></span></code></pre></div><ol start="6"><li>Complete the rest of the ad campaign setup.</li></ol><p>Some ad formats such as Carousel format can handle multiple deep links. To have link performance data on each image or component of the advertisement, create multiple Branch Ad links to be used in each part of the multiple link advertisement format. This format is useful if you want to drive customers to different content pieces or products.</p><h4 id="video-views-campaign-setup" tabindex="-1">Video Views Campaign Setup <a class="header-anchor" href="#video-views-campaign-setup" aria-label="Permalink to &quot;Video Views Campaign Setup&quot;">​</a></h4><h5 id="configure-an-ad-2" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad-2" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up Facebook Video Views Campaigns, you will need to insert your Branch Display Ad Link as the Website destination for the created ad.</p><h5 id="create-your-campaign-2" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign-2" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li><p>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</p></li><li><p>Select <strong>Video Views</strong> as the campaign marketing objective.</p></li><li><p>Continue with campaign creation selecting the app to advertise, audience, placement, and budget. Then press continue to enter the Advert creation step.</p></li><li><p>Now select an advertisement format and customize your ad</p></li><li><p>Now add your Branch Link to your advertisement</p><ul><li>Select the <strong>Add a Website URL</strong> checkbox and copy your Branch Ad Link into the <strong>Website URL</strong> field.</li></ul></li></ol><p>.png&quot;)</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- If you selected to add a full screen Canvas advertisement, add your Branch Ad link as the &lt;span class=&quot;notranslate&quot;&gt;**Destination URL**&lt;/span&gt; for your canvas advertisement components</span></span></code></pre></div><ol start="6"><li>Complete the rest of the ad campaign setup.</li></ol><p>Some ad formats such as Carousel format can handle multiple deep links. To have link performance data on each image or component of the advertisement, create multiple Branch Ad links to be used in each part of the multiple link advertisement format. This format is useful if you want to drive customers to different content pieces or products.</p><h4 id="lead-generation-campaign-setup" tabindex="-1">Lead Generation Campaign Setup <a class="header-anchor" href="#lead-generation-campaign-setup" aria-label="Permalink to &quot;Lead Generation Campaign Setup&quot;">​</a></h4><h5 id="configure-an-ad-3" tabindex="-1">Configure an Ad <a class="header-anchor" href="#configure-an-ad-3" aria-label="Permalink to &quot;Configure an Ad&quot;">​</a></h5><p>To set up Facebook Lead Generation Campaigns, you will need to insert your Branch Ad Link as the Website destination for the created ad. After users fill out the lead form, they&#39;ll be directed to your website or app after through the Branch Ad link.</p><h5 id="create-your-campaign-3" tabindex="-1">Create Your Campaign <a class="header-anchor" href="#create-your-campaign-3" aria-label="Permalink to &quot;Create Your Campaign&quot;">​</a></h5><ol><li><p>Navigate to <a href="https://www.facebook.com/ads/create" target="_blank" rel="noreferrer">https://www.facebook.com/ads/create</a> while logged in to the account that owns your Facebook app.</p></li><li><p>Select <strong>Lead Generation</strong> as the campaign marketing objective.</p></li><li><p>Continue with campaign creation selecting the app to advertise, audience, placement, and budget. Then press continue to enter the Advert creation step.</p></li><li><p>Now select an advertisement format and customize your ad</p></li><li><p>Enter the Lead form creation portal and setup your form.</p></li><li><p>On the final &quot;Thank you&quot; screen, locate and paste your Branch Ad Link into the <strong>Website link</strong> field.</p></li><li><p>Complete the rest of the ad campaign setup.</p></li></ol><h4 id="view-your-data" tabindex="-1">View Your Data <a class="header-anchor" href="#view-your-data" aria-label="Permalink to &quot;View Your Data&quot;">​</a></h4><p>The <a href="https://dashboard.branch.io/ads/analytics" target="_blank" rel="noreferrer">Ads Analytics Page</a> on the Branch dashboard provides an interactive time series graph and table to view the performance of your Ad campaigns.</p><p>The table shows summary data on the performance of each Ad campaign. On the right top side of the table you can find a <strong>download button</strong> to retrieve the chart&#39;s content as a CSV file.</p><div class="info custom-block"><p class="custom-block-title">Interacting with your data</p><p>Breakdown and compare aspects of your Ad campaigns&#39; performance by using the <code>Compare by +</code> button to add a parameter to split the data displayed data by.</p></div><p>Then use the <code>and +</code> button to refine the data displayed to gain deeper insight into the performance of your Ad campaigns.</p><h3 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h3><p>We now have a dedicated <a href="./facebook-faq-and-advanced-options.html">FAQ page for Facebook app ads</a>. If you are having any issues with app ads, please review the FAQ.</p><p>If you are having issues with web-only ads, you can check out the FAQ.</p>',63)])])}const m=a(i,[["render",r]]);export{u as __pageData,m as default};
